"use client";
import { useState } from "react";
import { Doctor, BookingFormData } from "../../types";
import { formatCurrency, generateAppointmentId } from "../../lib/utils";
import Button from "../ui/Button";

interface Props {
  doctor: Doctor;
  slot: string;
  onBack: () => void;
}

type Errors = Partial<Record<keyof BookingFormData, string>>;

function Field({ label, required, error, children }: {
  label: string; required?: boolean; error?: string; children: React.ReactNode;
}) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
      <label style={{ fontSize: 11, fontWeight: 600, color: "#64748b", letterSpacing: 1, textTransform: "uppercase" as const }}>
        {label}{required && <span style={{ color: "#f87171", marginLeft: 3 }}>*</span>}
      </label>
      {children}
      {error && <p style={{ color: "#f87171", fontSize: 12 }}>{error}</p>}
    </div>
  );
}

const inputStyle: React.CSSProperties = {
  width: "100%",
  background: "rgba(14, 28, 54, 0.8)",
  border: "1px solid rgba(56, 189, 248, 0.15)",
  borderRadius: 12,
  padding: "11px 16px",
  color: "#f1f5f9",
  fontSize: 14,
  fontFamily: "DM Sans, sans-serif",
  outline: "none",
  transition: "border-color 0.2s, box-shadow 0.2s",
  boxSizing: "border-box" as const,
};

export default function BookingForm({ doctor, slot, onBack }: Props) {
  const [form, setForm] = useState<BookingFormData>({
    fullName: "", idType: "nic", nic: "", passport: "",
    email: "", phone: "", address: "", notes: "",
  });
  const [errors, setErrors]       = useState<Errors>({});
  const [confirmed, setConfirmed] = useState(false);
  const [loading, setLoading]     = useState(false);
  const [appointmentId]           = useState(generateAppointmentId());

  const set = <K extends keyof BookingFormData>(key: K, value: BookingFormData[K]) =>
    setForm(f => ({ ...f, [key]: value }));

  const focusInput = (e: React.FocusEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    e.target.style.borderColor = "rgba(14,165,233,0.5)";
    e.target.style.boxShadow = "0 0 0 3px rgba(14,165,233,0.1)";
  };
  const blurInput = (e: React.FocusEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    e.target.style.borderColor = "rgba(56,189,248,0.15)";
    e.target.style.boxShadow = "none";
  };

  const validate = (): Errors => {
    const e: Errors = {};
    if (!form.fullName.trim()) e.fullName = "Full name is required";
    if (form.idType === "nic" && !form.nic.trim()) e.nic = "NIC number is required";
    if (form.idType === "passport" && !form.passport.trim()) e.passport = "Passport number is required";
    if (!form.email.trim() || !/\S+@\S+\.\S+/.test(form.email)) e.email = "Valid email is required";
    if (!form.phone.trim()) e.phone = "Phone number is required";
    if (!form.address.trim()) e.address = "Address is required";
    return e;
  };

  const handleSubmit = async () => {
    const e = validate();
    if (Object.keys(e).length) { setErrors(e); return; }
    setLoading(true);
    await new Promise(r => setTimeout(r, 1400));
    setLoading(false);
    setConfirmed(true);
  };

  const totalFee = doctor.fee + doctor.serviceFee;

  /* ── Confirmation ── */
  if (confirmed) {
    return (
      <div className="animate-scale-in" style={{ textAlign: "center", padding: "48px 24px" }}>
        <div style={{
          width: 80,
          height: 80,
          borderRadius: "50%",
          background: "linear-gradient(135deg, rgba(34,197,94,0.2), rgba(74,222,128,0.1))",
          border: "1px solid rgba(74,222,128,0.3)",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          fontSize: 36,
          margin: "0 auto 24px",
          boxShadow: "0 0 40px rgba(34,197,94,0.2)",
        }}>
          ✓
        </div>

        <h2 style={{ fontFamily: "Syne, sans-serif", fontWeight: 800, fontSize: 26, color: "#4ade80", marginBottom: 8 }}>
          Appointment Confirmed!
        </h2>
        <p style={{ color: "#64748b", marginBottom: 4, fontSize: 14 }}>
          Booking ID: <span style={{ color: "#38bdf8", fontFamily: "monospace", fontWeight: 700 }}>{appointmentId}</span>
        </p>
        <p style={{ color: "#64748b", marginBottom: 32, fontSize: 14 }}>
          Receipt sent to <span style={{ color: "#f1f5f9", fontWeight: 600 }}>{form.email}</span>
        </p>

        {/* Receipt card */}
        <div className="glass" style={{ padding: 24, maxWidth: 380, margin: "0 auto 24px", textAlign: "left" }}>
          {([ 
            ["Doctor", doctor.name],
            ["Specialization", doctor.specialization],
            ["Hospital", doctor.hospital],
            ["Time Slot", slot],
            ["Patient", form.fullName],
            [form.idType === "nic" ? "NIC" : "Passport", form.idType === "nic" ? form.nic : form.passport],
            ["Consultation Fee", formatCurrency(doctor.fee)],
            ["Service Charge", formatCurrency(doctor.serviceFee)],
            ["Total", formatCurrency(totalFee)],
          ] as [string, string][]).map(([label, value], i, arr) => (
            <div key={label} style={{
              display: "flex",
              justifyContent: "space-between",
              padding: "10px 0",
              borderBottom: i < arr.length - 1 ? "1px solid rgba(56,189,248,0.07)" : "none",
            }}>
              <span style={{ color: "#475569", fontSize: 13 }}>{label}</span>
              <span style={{
                fontSize: 13,
                fontWeight: 600,
                color: label === "Total" ? "#4ade80" : "#f1f5f9",
              }}>{value}</span>
            </div>
          ))}
        </div>

        <div style={{
          background: "rgba(14,165,233,0.08)",
          border: "1px solid rgba(56,189,248,0.15)",
          borderRadius: 12,
          padding: "14px 20px",
          maxWidth: 380,
          margin: "0 auto",
          fontSize: 13,
          color: "#38bdf8",
        }}>
          📲 WhatsApp confirmation sent to <strong>{form.phone}</strong>. Please arrive 10 mins early.
        </div>
      </div>
    );
  }

  /* ── Form ── */
  return (
    <div>
      <Button variant="ghost" size="sm" onClick={onBack} style={{ marginBottom: 20 }}>
        ← Back to Time Slots
      </Button>

      {/* Summary banner */}
      <div className="glass animate-fade-up" style={{
        padding: "16px 22px",
        marginBottom: 20,
        display: "flex",
        alignItems: "center",
        gap: 16,
        background: "linear-gradient(135deg, rgba(14,165,233,0.08), rgba(99,102,241,0.05))",
      }}>
        <div style={{
          width: 44,
          height: 44,
          borderRadius: 14,
          background: "linear-gradient(135deg, #0ea5e9, #6366f1)",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          color: "#fff",
          fontWeight: 800,
          fontSize: 14,
          fontFamily: "Syne, sans-serif",
          flexShrink: 0,
          boxShadow: "0 0 16px rgba(14,165,233,0.3)",
        }}>
          {doctor.initials}
        </div>
        <div style={{ flex: 1, minWidth: 0 }}>
          <p style={{ fontWeight: 700, color: "#f1f5f9", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
            {doctor.name}
          </p>
          <p style={{ color: "#64748b", fontSize: 13 }}>{doctor.hospital} · {slot}</p>
        </div>
        <p style={{ fontFamily: "Syne, sans-serif", fontWeight: 800, fontSize: 18, color: "#4ade80", flexShrink: 0 }}>
          {formatCurrency(doctor.fee)}
        </p>
      </div>

      <div className="glass animate-fade-up-2" style={{ padding: 28 }}>
        <p style={{ fontSize: 11, fontWeight: 700, color: "#38bdf8", letterSpacing: 2, textTransform: "uppercase", marginBottom: 24 }}>
          📋 Patient Details
        </p>

        <div style={{ display: "flex", flexDirection: "column", gap: 18 }}>
          <Field label="Full Name" required error={errors.fullName}>
            <input type="text" placeholder="As per NIC / Passport"
              value={form.fullName} onChange={e => set("fullName", e.target.value)}
              style={inputStyle} onFocus={focusInput} onBlur={blurInput} />
          </Field>

          {/* ID toggle */}
          <div>
            <label style={{ fontSize: 11, fontWeight: 600, color: "#64748b", letterSpacing: 1, textTransform: "uppercase", display: "block", marginBottom: 8 }}>
              ID Type <span style={{ color: "#f87171" }}>*</span>
            </label>
            <div style={{ display: "flex", gap: 10 }}>
              {(["nic", "passport"] as const).map(type => (
                <button
                  key={type}
                  onClick={() => set("idType", type)}
                  style={{
                    flex: 1,
                    padding: "10px",
                    borderRadius: 12,
                    fontSize: 13,
                    fontWeight: 700,
                    fontFamily: "DM Sans, sans-serif",
                    cursor: "pointer",
                    transition: "all 0.2s",
                    border: form.idType === type
                      ? "1px solid rgba(14,165,233,0.6)"
                      : "1px solid rgba(56,189,248,0.1)",
                    background: form.idType === type
                      ? "linear-gradient(135deg, rgba(14,165,233,0.2), rgba(56,189,248,0.1))"
                      : "rgba(14,28,54,0.5)",
                    color: form.idType === type ? "#38bdf8" : "#64748b",
                    boxShadow: form.idType === type ? "0 0 16px rgba(14,165,233,0.15)" : "none",
                  }}
                >
                  {type === "nic" ? "NIC" : "Passport"}
                </button>
              ))}
            </div>
          </div>

          {form.idType === "nic" ? (
            <Field label="NIC Number" required error={errors.nic}>
              <input type="text" placeholder="e.g. 199012345678 or 901234567V"
                value={form.nic} onChange={e => set("nic", e.target.value)}
                style={inputStyle} onFocus={focusInput} onBlur={blurInput} />
            </Field>
          ) : (
            <Field label="Passport Number" required error={errors.passport}>
              <input type="text" placeholder="e.g. N1234567"
                value={form.passport} onChange={e => set("passport", e.target.value)}
                style={inputStyle} onFocus={focusInput} onBlur={blurInput} />
            </Field>
          )}

          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
            <Field label="Email" required error={errors.email}>
              <input type="email" placeholder="you@example.com"
                value={form.email} onChange={e => set("email", e.target.value)}
                style={inputStyle} onFocus={focusInput} onBlur={blurInput} />
            </Field>
            <Field label="Phone" required error={errors.phone}>
              <input type="tel" placeholder="+94 77 123 4567"
                value={form.phone} onChange={e => set("phone", e.target.value)}
                style={inputStyle} onFocus={focusInput} onBlur={blurInput} />
            </Field>
          </div>

          <Field label="Address" required error={errors.address}>
            <input type="text" placeholder="No. 12, Galle Rd, Colombo 03"
              value={form.address} onChange={e => set("address", e.target.value)}
              style={inputStyle} onFocus={focusInput} onBlur={blurInput} />
          </Field>

          <Field label="Notes for Doctor (Optional)">
            <textarea
              placeholder="Any symptoms, allergies, or notes..."
              value={form.notes}
              onChange={e => set("notes", e.target.value)}
              rows={3}
              style={{ ...inputStyle, resize: "none" }}
              onFocus={focusInput}
              onBlur={blurInput}
            />
          </Field>

          {/* Fee breakdown */}
          <div style={{
            background: "rgba(14,28,54,0.6)",
            borderRadius: 14,
            padding: "18px 20px",
            border: "1px solid rgba(56,189,248,0.08)",
          }}>
            {[
              ["Consultation Fee", formatCurrency(doctor.fee)],
              ["Service Charge",   formatCurrency(doctor.serviceFee)],
            ].map(([label, value]) => (
              <div key={label} style={{ display: "flex", justifyContent: "space-between", marginBottom: 10, fontSize: 14 }}>
                <span style={{ color: "#64748b" }}>{label}</span>
                <span style={{ color: "#e2e8f0" }}>{value}</span>
              </div>
            ))}
            <div style={{ height: 1, background: "rgba(56,189,248,0.1)", marginBottom: 10 }} />
            <div style={{ display: "flex", justifyContent: "space-between" }}>
              <span style={{ fontWeight: 700, color: "#f1f5f9", fontSize: 15 }}>Total</span>
              <span style={{
                fontFamily: "Syne, sans-serif",
                fontWeight: 800,
                fontSize: 18,
                background: "linear-gradient(135deg, #4ade80, #22c55e)",
                WebkitBackgroundClip: "text",
                WebkitTextFillColor: "transparent",
                backgroundClip: "text",
              }}>
                {formatCurrency(totalFee)}
              </span>
            </div>
          </div>

          <p style={{ color: "#475569", fontSize: 12, textAlign: "center" }}>
            📧 Receipt emailed · 📲 WhatsApp confirmation sent to your phone
          </p>

          <Button size="lg" style={{ width: "100%" }} onClick={handleSubmit} disabled={loading}>
            {loading ? "Confirming..." : "Confirm Appointment & Pay →"}
          </Button>
        </div>
      </div>
    </div>
  );
}